import React, { useEffect, useState } from 'react';
import { getHistory } from '../services/resume';
import { 
  DocumentTextIcon, 
  ChartBarIcon, 
  AcademicCapIcon,
  ArrowPathIcon 
} from '@heroicons/react/24/outline';
import StatsCard from '../components/Dashboard/StatsCard';
import HistoryList from '../components/Dashboard/HistoryList';

const Dashboard = () => {
  const [history, setHistory] = useState([]);
  const [stats, setStats] = useState({
    total: 0,
    avgAts: 0,
    highestMatch: 0
  });
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    loadHistory();
  }, []);

  const loadHistory = async () => {
    try {
      const data = await getHistory();
      setHistory(data);
      
      if (data.length > 0) {
        const avg = data.reduce((acc, curr) => acc + curr.atsScore, 0) / data.length;
        const highest = Math.max(...data.map(item => item.matchPercentage));
        setStats({
          total: data.length,
          avgAts: Math.round(avg * 10) / 10,
          highestMatch: highest
        });
      }
    } catch (error) {
      console.error('Failed to load history:', error);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="text-center">
          <ArrowPathIcon className="h-12 w-12 text-indigo-600 animate-spin mx-auto mb-4" />
          <p className="text-gray-600">Loading your dashboard...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
      <div className="mb-8">
        <h1 className="text-3xl font-bold text-gray-900">Dashboard</h1>
        <p className="text-gray-600 mt-1">Welcome back! Here's an overview of your resume analyses.</p>
      </div>

      {/* Stats Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
        <StatsCard 
          title="Total Analyses"
          value={stats.total}
          icon={<DocumentTextIcon className="h-6 w-6 text-indigo-600" />}
          color="indigo"
        />
        <StatsCard 
          title="Avg. ATS Score"
          value={`${stats.avgAts}%`}
          icon={<ChartBarIcon className="h-6 w-6 text-green-600" />}
          color="green"
        />
        <StatsCard 
          title="Highest Match"
          value={`${stats.highestMatch}%`}
          icon={<AcademicCapIcon className="h-6 w-6 text-purple-600" />}
          color="purple"
        />
      </div>

      {/* Recent History */}
      <div className="bg-white rounded-xl shadow-md p-6">
        <h2 className="text-xl font-semibold text-gray-900 mb-6">Recent History</h2>
        <HistoryList history={history} />
      </div>
    </div>
  );
};

export default Dashboard;
